function _vm_check {
    try {
        $r=@('VBoxService','vmtoolsd','vmware','qemu-ga','xen','parallels')
        $p=(Get-Process | Select-Object -ExpandProperty Name) -join ' '
        if ($r | Where-Object {$p -match $_}) { return $true }
        $m=(Get-WmiObject Win32_NetworkAdapterConfiguration | Select-Object -ExpandProperty MACAddress) -join ' '
        if ($m -match '08:00:27|00:0c:29|00:1c:42|00:16:3e|52:54:00') { return $true }
    } catch { }
    return $false
}
if (_vm_check) {
    Write-Error 'ERROR: This application cannot run on virtual machines.'
    exit 1
}

